    10→import { cn } from "@/lib/utils";
    11→
    12→interface Project {
    13→    id: string;
    14→    title?: string;
    15→    text: string;
    16→    description?: string;
    17→    color?: string;
    18→    globalScore?: number;
    19→    recommendation?: string;
    20→    confidenceLevel?: string;
    21→    viabilityScore?: number;
    22→    classification?: string;
    23→    timestamp: string;
    24→    isDemo?: boolean;
    25→    isArchived?: boolean;
    26→    analysis?: any;
    27→}
    28→
    29→function getProjectDecision(p: Project): string {
    30→    return p.recommendation ?? p.classification ?? "DRAFT";
    31→}
    32→
    33→function getProjectTitle(p: Project): string {
    34→    return p.title ?? p.text;
    35→}
