    37→export default function WorkspacePage() {
    38→    const router = useRouter();
    39→
    40→    const [projects, setProjects] = useState<Project[]>([]);
    41→    const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
    42→    const [searchQuery, setSearchQuery] = useState("");
    43→    const [activeFilter, setActiveFilter] = useState<string>("ALL");
    44→    const [sortBy, setSortBy] = useState<string>("date");
    45→    const [showArchived, setShowArchived] = useState(false);
    46→
    47→    // Detail overlay state
    48→    const [detailProject, setDetailProject] = useState<Project | null>(null);
    49→    const [detailOpen, setDetailOpen] = useState(false);
    50→
    51→    // Initial Load Logic
    52→    useEffect(() => {
    53→        const currentIdea = localStorage.getItem("k3rn_active_project");
    54→        const storedProjects = JSON.parse(localStorage.getItem("k3rn_projects") || "[]");
    55→
    56→        if (currentIdea) {
    57→            const idea = JSON.parse(currentIdea);
    58→            const exists = storedProjects.some((p: any) => p.timestamp === idea.timestamp);
    59→            if (!exists) {
    60→                const newProject: Project = {
    61→                    id: idea.id || crypto.randomUUID(),
    62→                    title: idea.title,
    63→                    text: idea.text || "",
    64→                    description: idea.description,
    65→                    globalScore: idea.globalScore ?? idea.analysis?.viabilityScore,
    66→                    recommendation: idea.recommendation ?? idea.analysis?.classification,
    67→                    confidenceLevel: idea.confidenceLevel,
    68→                    viabilityScore: idea.viabilityScore ?? idea.analysis?.viabilityScore,
    69→                    classification: idea.classification ?? idea.analysis?.classification,
    70→                    timestamp: idea.timestamp,
    71→                    isDemo: idea.isDemo,
    72→                    analysis: idea.analysis,
    73→                };
    74→                storedProjects.unshift(newProject);
    75→                localStorage.setItem("k3rn_projects", JSON.stringify(storedProjects));
    76→                localStorage.removeItem("k3rn_active_project");
    77→            }
    78→        }
    79→
    80→        if (storedProjects.length === 0) {
    81→            const mocks: Project[] = [
    82→                { id: "1", title: "Drone Fleet SaaS Platform", text: "Plateforme SaaS de gestion de flottes de drones autonomes", globalScore: 92, recommendation: "GO", confidenceLevel: "HIGH", timestamp: new Date().toISOString(), isDemo: true, description: "A comprehensive solution for autonomous drone logistics, featuring real-time telemetry, AI-driven pathfinding, and predictive maintenance.", analysis: { axes: [{ label: "Probleme", score: 9 }, { label: "Marche", score: 8 }, { label: "Differenciation", score: 10 }, { label: "Faisabilite", score: 8 }, { label: "Business Model", score: 9 }, { label: "Founder Fit", score: 9 }], synthesis: "Ce projet presente un potentiel exceptionnel. Le marche de la logistique drone est en pleine expansion avec un CAGR de 28%. La differenciation technique est maximale grace a l'integration d'IA pour le pathfinding et la maintenance predictive. Le business model SaaS assure des revenus recurrents. Recommandation : accelerer le developpement du MVP et securiser un premier contrat pilote.", risks: ["Reglementation aerienne complexe et en evolution — risque de delais reglementaires", "Cout d'infrastructure eleve pour le deploiement initial (stations de charge, communication)", "Competition potentielle des geants tech (Amazon Prime Air, Wing/Alphabet)", "Dependance aux conditions meteorologiques pour les operations quotidiennes"] } },
    83→                { id: "2", title: "NFT Patent Marketplace", text: "Marketplace NFT pour brevets industriels", globalScore: 38, recommendation: "KILL", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 86400000).toISOString(), isDemo: true, description: "Attempting to tokenize IP rights on the blockchain. Initial market validation suggests low demand.", analysis: { synthesis: "Le concept de tokenisation des brevets sur blockchain ne repond pas a un besoin reel du marche. Les acteurs industriels privilegient les canaux traditionnels de gestion de PI.", risks: ["Absence de demande marche validee", "Complexite juridique de la tokenisation de PI", "Modele economique non viable a long terme"] } },
    84→                { id: "3", title: "AI Film Script Generator", text: "IA generative pour scripts de films", globalScore: 78, recommendation: "EXPLORE", confidenceLevel: "MEDIUM", timestamp: new Date(Date.now() - 172800000).toISOString(), isDemo: true, description: "Leveraging LLMs for creative writing assistance. The prototype shows promise but lacks structure.", analysis: { synthesis: "L'outil montre un potentiel creatif interessant mais necessite une structuration plus poussee du workflow narratif. Le marche de l'IA creative est en croissance rapide.", risks: ["Qualite narrative encore insuffisante pour un usage professionnel", "Concurrence forte des outils existants (ChatGPT, Jasper)", "Questions ethiques sur la propriete intellectuelle generee par IA"] } },
    85→                { id: "4", title: "MeowNet - Social Network for Cats", text: "Reseau social pour chats (MeowNet)", globalScore: 22, recommendation: "PARK", confidenceLevel: "LOW", timestamp: new Date(Date.now() - 432000000).toISOString(), isDemo: true, description: "Niche social network. Market size is questionable despite high engagement potential." },
    86→                { id: "5", title: "Quantum Encryption Key", text: "Cle de chiffrement quantique", globalScore: 88, recommendation: "GO", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 500000000).toISOString(), isDemo: true, description: "Next-gen security infrastructure for fintech. Critical need in the post-quantum era.", analysis: { axes: [{ label: "Probleme", score: 10 }, { label: "Marche", score: 9 }, { label: "Differenciation", score: 8 }, { label: "Faisabilite", score: 7 }, { label: "Business Model", score: 9 }, { label: "Founder Fit", score: 8 }], synthesis: "Infrastructure de securite critique pour l'ere post-quantique. Le marche fintech est pret pour cette transition. La faisabilite technique est le principal defi.", risks: ["Complexite technique de l'implementation quantique", "Cout de R&D eleve avant commercialisation", "Risque de timing — marche pas encore pret massivement"] } },
    87→            ];
    88→            setProjects(mocks);
    89→        } else {
    90→            setProjects(storedProjects);
    91→        }
    92→    }, []);
    93→
    94→    const filteredProjects = useMemo(() => {
    95→        let result = projects.filter((p) => {
    96→            // Filter by archived status
    97→            const matchesArchiveStatus = showArchived ? p.isArchived === true : p.isArchived !== true;
    98→
    99→            const q = searchQuery.toLowerCase();
   100→            const matchesSearch =
   101→                getProjectTitle(p).toLowerCase().includes(q) ||
   102→                p.text.toLowerCase().includes(q) ||
   103→                getProjectDecision(p).toLowerCase().includes(q);
   104→
   105→            const matchesFilter = activeFilter === "ALL" || getProjectDecision(p) === activeFilter;
   106→
   107→            return matchesArchiveStatus && matchesSearch && matchesFilter;
   108→        });
   109→
   110→        if (sortBy === "score") {
   111→            result = [...result].sort((a, b) => (b.globalScore ?? 0) - (a.globalScore ?? 0));
   112→        } else {
   113→            result = [...result].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
   114→        }
   115→
   116→        return result;
   117→    }, [projects, searchQuery, activeFilter, sortBy, showArchived]);
   118→
   119→    // Welcome hero stats
   120→    const goCount = projects.filter((p) => getProjectDecision(p) === "GO").length;
   121→    const attentionCount = projects.filter((p) => {
   122→        const d = getProjectDecision(p);
   123→        return d === "EXPLORE" || d === "KILL";
   124→    }).length;
   125→
   126→    // Save handler for detail overlay
   127→    function handleSaveProject(id: string, updates: { title?: string; description?: string }) {
   128→        const updated = projects.map((p) =>
   129→            p.id === id ? { ...p, ...updates } : p
   130→        );
   131→        setProjects(updated);
   132→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   133→    }
   134→
   135→    // Archive handler
   136→    function handleArchive(id: string) {
   137→        const updated = projects.map((p) =>
   138→            p.id === id ? { ...p, isArchived: true } : p
   139→        );
   140→        setProjects(updated);
   141→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   142→        setDetailOpen(false);
   143→        setDetailProject(null);
   144→    }
   145→
   146→    // Unarchive handler
   147→    function handleUnarchive(id: string) {
   148→        const updated = projects.map((p) =>
   149→            p.id === id ? { ...p, isArchived: false } : p
   150→        );
   151→        setProjects(updated);
   152→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   153→        setDetailOpen(false);
   154→        setDetailProject(null);
   155→    }
   156→
   157→    // Delete handler
   158→    function handleDelete(id: string) {
   159→        const updated = projects.filter((p) => p.id !== id);
   160→        setProjects(updated);
   161→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   162→        setDetailOpen(false);
   163→        setDetailProject(null);
   164→    }
   165→
   166→    return (
   167→        <div className="min-h-screen bg-background text-foreground font-sans selection:bg-[--color-brand-primary]/30 flex flex-col overflow-x-hidden">
   168→            <SiteHeader variant="app" />
   169→
   170→            <main className="relative z-[1] flex-1 pt-12 pb-40 px-8 w-full max-w-[1400px] mx-auto">
   171→
   172→                {/* Welcome Hero */}
   173→                <div
   174→                    className="mb-12 rounded-[var(--radius-2xl)] p-8 animate-in fade-in slide-in-from-bottom-4 duration-500"
   175→                    style={{
   176→                        background: "var(--color-bg-secondary)",
   177→                        border: "1px solid var(--color-border-subtle)",
   178→                        boxShadow: "inset 0 1px 0 rgba(0,0,0,0.2), inset 0 -1px 0 rgba(255,255,255,0.02)",
   179→                    }}
   180→                >
   181→                    <h1 className="text-[2.5rem] font-light text-white tracking-[-0.02em] leading-[1.1] mb-3">
   182→                        Bonjour, Thomas.
   183→                    </h1>
   184→                    <div className="flex items-center justify-between">
   185→                        <p className="text-base text-[--color-text-muted] flex items-center gap-2">
   186→                            <strong className="text-[--color-text-secondary] font-medium">{projects.filter(p => !p.isArchived).length}</strong> dossier{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""} actif{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""}
   187→                            {" "}&middot;{" "}
   188→                            <strong className="text-[--color-text-secondary] font-medium">{goCount}</strong> projet{goCount !== 1 ? "s" : ""} valide{goCount !== 1 ? "s" : ""} GO
   189→                            {" "}&middot;{" "}
   190→                            <strong className="text-[--color-text-secondary] font-medium">{attentionCount}</strong> necessite{attentionCount !== 1 ? "nt" : ""} votre attention
   191→                        </p>
   192→                        <button
   193→                            onClick={() => setShowArchived(!showArchived)}
   194→                            className="group inline-flex items-center gap-2 px-4 py-2 bg-transparent text-[--color-text-muted] border border-[--color-border-default] rounded-[var(--radius-md)] text-sm font-medium transition-all duration-300 hover:text-white hover:bg-[rgba(255,255,255,0.06)] hover:border-[--color-border-strong] hover:scale-[1.02] active:scale-[0.98]"
   195→                        >
   196→                            <Archive className="w-4 h-4 transition-transform duration-300 group-hover:scale-110" />
   197→                            {showArchived ? "Dossiers actifs" : "Dossiers archivés disponibles"}
   198→                        </button>
   199→                    </div>
   200→                </div>
   201→
   202→                {/* Grid */}
   203→                <div className={cn(
   204→                    "animate-in fade-in zoom-in-95 duration-500",
   205→                    viewMode === "grid"
   206→                        ? "grid gap-6"
   207→                        : "grid grid-cols-1 gap-4"
   208→                )}
   209→                    style={viewMode === "grid" ? { gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))" } : undefined}
   210→                >
   211→                    {/* New Project Card - Only show when NOT in archived view */}
   212→                    {!showArchived && (
   213→                        <ProCard
   214→                            isNew
   215→                            onClick={() => router.push('/capture')}
   216→                        />
   217→                    )}
   218→
   219→                    {/* Project Cards */}
   220→                    {filteredProjects.map((project) => (
   221→                        <ProCard
   222→                            key={project.id}
   223→                            project={project}
   224→                            onClick={() => {
   225→                                setDetailProject(project);
   226→                                setDetailOpen(true);
   227→                            }}
   228→                        />
   229→                    ))}
   230→                </div>
   231→            </main>
   232→
   233→            {/* Floating Command Dock */}
   234→            <FloatingDock
   235→                viewMode={viewMode}
   236→                setViewMode={setViewMode}
   237→                searchQuery={searchQuery}
   238→                setSearchQuery={setSearchQuery}
   239→                activeFilter={activeFilter}
   240→                setActiveFilter={setActiveFilter}
   241→                sortBy={sortBy}
   242→                setSortBy={setSortBy}
   243→                onNewProject={() => router.push('/capture')}
   244→            />
   245→
   246→            {/* Project Detail Overlay */}
   247→            <ProjectDetailOverlay
   248→                project={detailProject}
   249→                open={detailOpen}
   250→                onClose={() => {
   251→                    setDetailOpen(false);
   252→                    setDetailProject(null);
   253→                }}
   254→                onSave={handleSaveProject}
   255→                onArchive={handleArchive}
   256→                onUnarchive={handleUnarchive}
   257→                onDelete={handleDelete}
   258→            />
   259→        </div>
   260→    );
   261→}
   262→

