     1→import { create } from 'zustand';
     2→import { GlyphSpec, GlyphPiece, GlyphPieceType } from '../core/glyphSpec.schema';
     3→import { INITIAL_GLYPH, LETTER_PRESETS } from '../core/presets';
     4→
     5→type GlyphStore = {
     6→    spec: GlyphSpec;
     7→    selectedPieceId: string | null;
     8→    selectedPiece: GlyphPiece | null;
     9→    hoveredPieceId: string | null;
    10→
    11→    updateGlobal: (updates: Partial<GlyphSpec['global']>) => void;
    12→    updatePiece: (id: string, updates: Partial<GlyphPiece>) => void;
    13→    selectPiece: (id: string | null) => void;
    14→    setHoveredPiece: (id: string | null) => void;
    15→    toggleExplode: () => void;
    16→    toggleShowParts: () => void;
    17→    reset: () => void;
    18→
    19→    // V2 Actions
    20→    setCharacter: (char: string) => void;
    21→    addPiece: (type: GlyphPieceType) => void;
    22→    removePiece: (id: string) => void;
    23→};
    24→
    25→export const useGlyphStore = create<GlyphStore>((set, get) => ({
    26→    spec: INITIAL_GLYPH,
    27→    selectedPieceId: null,
    28→    selectedPiece: null,
    29→    hoveredPieceId: null,
    30→
    31→    updateGlobal: (updates) =>
    32→        set((state) => ({
    33→            spec: {
    34→                ...state.spec,
    35→                global: { ...state.spec.global, ...updates },
    36→            },
    37→        })),
    38→
    39→    updatePiece: (id, updates) =>
    40→        set((state) => {
    41→            const newPieces = state.spec.pieces.map((p) =>
    42→                p.id === id ? { ...p, ...updates } : p
    43→            );
    44→            const newSelected = newPieces.find((p) => p.id === state.selectedPieceId) || null;
    45→
    46→            return {
    47→                spec: { ...state.spec, pieces: newPieces },
    48→                selectedPiece: newSelected,
    49→            };
    50→        }),
    51→
    52→    selectPiece: (id) =>
    53→        set((state) => ({
    54→            selectedPieceId: id,
    55→            selectedPiece: state.spec.pieces.find((p) => p.id === id) || null,
    56→        })),
    57→
    58→    setHoveredPiece: (id) => set({ hoveredPieceId: id }),
    59→
    60→    toggleExplode: () =>
    61→        set((state) => {
    62→            const current = state.spec.global.explode;
    63→            const next = current > 0 ? 0 : 0.6;
    64→            return {
    65→                spec: {
    66→                    ...state.spec,
    67→                    global: { ...state.spec.global, explode: next },
    68→                },
    69→            };
    70→        }),
    71→
    72→    toggleShowParts: () =>
    73→        set((state) => ({
    74→            spec: {
    75→                ...state.spec,
    76→                global: { ...state.spec.global, showParts: !state.spec.global.showParts },
    77→            },
    78→        })),
    79→
    80→    setCharacter: (char) => set((state) => {
    81→        const preset = LETTER_PRESETS[char.toUpperCase()];
    82→        if (!preset) return state; // Handle unknown char
    83→
    84→        return {
    85→            spec: {
    86→                ...state.spec,
    87→                global: { ...state.spec.global, character: char.toUpperCase() },
    88→                pieces: preset,
    89→            },
    90→            selectedPieceId: null,
    91→            selectedPiece: null,
    92→        };
    93→    }),
    94→
    95→    addPiece: (type) => set((state) => {
    96→        const newId = `${type}-${Date.now().toString(36)}`;
    97→        const newPiece: GlyphPiece = {
    98→            id: newId,
    99→            type: type,
   100→            enabled: true,
   101→            anchor: { x: 0.5, y: 0.5 },
   102→            length: type === 'rect' ? 0.5 : 0.2,
   103→            angleDeg: 0,
